const sheetEmails = new Set(
  $('Get row(s) in sheet').all().map(i => i.json.Email?.toLowerCase().trim()).filter(Boolean)
);
const sheetNoms = new Set(
  $('Get row(s) in sheet').all().map(i => i.json.Nom?.toLowerCase().trim()).filter(Boolean)
);

const leads = $('Code in JavaScript5').all().map(i => i.json);
const seenEmail = new Set();

return leads
  .filter(lead => {
    const email = lead.Email?.toLowerCase().trim();
    if (!email || sheetEmails.has(email) || seenEmail.has(email) || sheetNoms.has(lead.Nom?.toLowerCase().trim())) {
      return false;
    }
    seenEmail.add(email);
    return true;
  })
  .map(lead => ({ json: lead }));

function cleanSpaces(s){
  return (s || "").toString().replace(/\s+/g," ").trim();
}

function normalizePhone(p){
  return cleanSpaces(p).replace(/[^\d+]/g,""); // garde + et chiffres
}

function normalizeAddress(a){
  return cleanSpaces(a)
    .toLowerCase()
    .replace(/[’']/g,"'")
    .replace(/,\s*france$/i,"")
    .replace(/\s+/g," ");
}

function getDomain(email){
  const e = (email || "").toString().trim().toLowerCase();
  const m = e.match(/@([^>\s]+)/);
  return m ? m[1] : "";
}

function getLocalpart(email){
  const e = (email || "").toString().trim().toLowerCase();
  return e.includes("@") ? e.split("@")[0] : "";
}

function getHostFromUrl(url){
  if (!url) return "";
  try {
    const u = new URL(url);
    return (u.hostname || "").toLowerCase().replace(/^www\./,"");
  } catch {
    // au cas où l'URL est sans protocole
    try {
      const u = new URL("https://" + url);
      return (u.hostname || "").toLowerCase().replace(/^www\./,"");
    } catch { return ""; }
  }
}

const FREE_DOMAINS = new Set([
  "gmail.com","googlemail.com","yahoo.com","yahoo.fr","hotmail.com","outlook.com",
  "live.com","icloud.com","aol.com","proton.me","protonmail.com","gmx.com","gmx.fr"
]);

// nom “commercial” → query plus robuste pour Pappers
function cleanCompanyName(n, emailDomain, websiteUrl, email){
  let s = cleanSpaces(n);

  // 1️⃣ split intelligent sur " - " / " – " : si le préfixe est trop générique, on garde le suffixe
const partsDash = s.includes(" - ") ? s.split(" - ") : (s.includes(" – ") ? s.split(" – ") : null);
if (partsDash && partsDash.length >= 2) {
  const left = partsDash[0].trim();
  const right = partsDash.slice(1).join(" - ").trim();

  const leftLower = left.toLowerCase();

  // Si le préfixe contient des mots SEO (coiffeur/spa/etc.), il est souvent useless → prendre la partie droite
  const leftIsGeneric =
    /\b(coiffeur|coiffeuse|salon|spa|institut|massage|bio|barber)\b/i.test(leftLower) ||
    leftLower.length <= 12; // "Coiffeur Lyon" typiquement court et générique

  s = leftIsGeneric && right ? right : left;
}

  // 2️⃣ retire mots SEO fréquents
  s = s.replace(
    /\b(coiffeur|coiffeuse|salon|bio|paris|colorations?|v[ée]g[ée]tales?|v[ée]g[ée]tale)\b/gi,
    " "
  );

  // 3️⃣ retire chiffres isolés
  s = s.replace(/\b\d+\b/g, " ");

  // 4️⃣ retire petits mots parasites
  s = s.replace(/\b(et|de|du|des|la|le|les|à|a)\b/gi, " ");

  // 5️⃣ nettoyage final
  s = s
    .replace(/[’]/g,"'")
    .replace(/\s+/g," ")
    .trim();

  // 6️⃣ fallback si résultat trop faible
  const lettersCount = (s.match(/[a-zA-Z]/g) || []).length;
  if (s.length < 4 || lettersCount < 4) {

    const domain = (emailDomain || "").toString().toLowerCase();

    // ✅ si email gratuit (gmail, etc.) => NE PAS retourner "gmail"
    if (domain && FREE_DOMAINS.has(domain)) {
      const host = getHostFromUrl(websiteUrl);          // ex: les-fees-naturelles.com
      const hostBase = host ? host.split(".")[0] : "";  // ex: les-fees-naturelles
      if (hostBase && hostBase.length >= 4) return hostBase;

      const lp = getLocalpart(email); // ex: lesfeesnaturelles
      if (lp && lp.length >= 4) return lp;

      return s; // dernier recours
    }

    // ✅ email pro => ok d'utiliser le domaine
    const base = domain ? domain.split(".")[0] : "";
    return base ? base : s;
  }

  return s.slice(0, 60);
}

return items.map(item => {
  const j = item.json;
  const email = j["Email"];
  const domain = getDomain(email);
  const website = j["Site internet"];

  return {
    json: {
      ...j,
      phone_norm: normalizePhone(j["Téléphone international"]),
      addr_norm: normalizeAddress(j["Adresse complète"]),
      email_domain: domain,
      company_query: cleanCompanyName(j["Nom"], domain, website, email),
    }
  };
});

function norm(s){
  return (s || "")
    .toString()
    .toLowerCase()
    .replace(/[’']/g, "")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function host(url){
  const m = (url || "").toString().match(/^https?:\/\/([^\/?#]+)/i);
  return m ? m[1].toLowerCase() : "";
}

function baseDomainFromHost(h){
  const parts = (h || "").split(".");
  return parts.length >= 2 ? parts[parts.length - 2] : (h || "");
}

function baseDomainFromEmailDomain(d){
  const parts = (d || "").toString().toLowerCase().split(".");
  return parts.length >= 2 ? parts[parts.length - 2] : (d || "").toString().toLowerCase();
}

function pickAddressKey(addrNorm){
  // garde juste “75 rue claude decaen” pour matcher plus facilement
  const a = norm(addrNorm || "");
  if (!a) return "";
  const parts = a.split(" ");
  return parts.slice(0, 4).join(" "); // ex: "75 rue claude decaen"
}

return items.map(item => {
  const j = item.json;
  const results = Array.isArray(j.resultats) ? j.resultats : [];

  const leadCP = (j["Code postal"] || "").toString().trim();
  const leadAddrKey = pickAddressKey(j.addr_norm || j["Adresse complète"] || "");
  const emailKey = baseDomainFromEmailDomain(j.email_domain || "");
  const siteKey = baseDomainFromHost(host(j["Site internet"] || ""));
  const key = norm(emailKey || siteKey || j.company_query || j["Nom"] || "");

  let best = null;
  let bestScore = -1;

  for (const r of results) {
    let score = 0;

    const rName = norm(r.nom_entreprise || r.denomination || "");
    const rCP = (r.siege?.code_postal || "").toString().trim();
    const naf = (r.code_naf || "").toString();

    // A) match "clé" sur le NOM (faible si marque ≠ dénomination)
    if (key && rName.includes(key)) score += 30;

    // B) match CP sur siège (Paris toléré)
    if (leadCP && rCP) {
      if (leadCP === rCP) score += 20;
      else if (leadCP.startsWith("75") && rCP.startsWith("75")) score += 5;
    }

    // C) match sur établissements (signal fort)
    const etabs = Array.isArray(r.etablissements) ? r.etablissements : [];

    if (leadCP && etabs.some(e => (e.code_postal || "").toString().trim() === leadCP)) {
      score += 50; // énorme signal
    }

    if (leadAddrKey) {
      const hitAddr = etabs.some(e => norm(e.adresse_ligne_1 || "").includes(leadAddrKey));
      if (hitAddr) score += 70; // ultra signal
    }

    // D) bonus convention coiffure (si présent)
    const ccs = Array.isArray(r.conventions_collectives) ? r.conventions_collectives : [];
    if (ccs.some(cc => norm(cc.nom || "").includes("coiffure"))) score += 10;

    // E) bonus/malus NAF
    if (naf.startsWith("96.02")) score += 10;
    if (naf.startsWith("85.")) score -= 40;

    // F) actif bonus (si actif)
    if ((r.statut_consolide || "").toString().toLowerCase() === "actif") score += 5;

    if (score > bestScore) {
      bestScore = score;
      best = r;
    }
  }

  // Seuil abaissé car on score fort sur établissement
  const ok = best && bestScore >= 50;

  return {
    json: {
      ...j,
      pappers_best_score: bestScore,
      pappers_best: best || null,
      SIREN: ok ? best.siren : null,
      pappers_ok: !!ok
    }
  };
});

// Build retry query (smart):
// 1) Prefer professional email domain
// 2) Else website domain
// 3) Else company_query
// 4) Else Nom
// If retry_query === company_query → set null

// --- DOMAINES GRATUITS / WEBMAIL ---
const FREE_DOMAINS = new Set([
  // Google
  'gmail.com','googlemail.com',

  // Microsoft
  'hotmail.com','hotmail.fr','outlook.com','outlook.fr','live.com','live.fr','msn.com',

  // Yahoo
  'yahoo.com','yahoo.fr','ymail.com',

  // FAI FR
  'orange.fr','wanadoo.fr','voila.fr','laposte.net',
  'sfr.fr','bbox.fr','bouyguestelecom.fr',
  'free.fr','aliceadsl.fr','club-internet.fr',
  'numericable.fr','neuf.fr',

  // Proton
  'proton.me','protonmail.com','pm.me',

  // GMX
  'gmx.com','gmx.fr',

  // Apple
  'icloud.com','me.com','mac.com',

  // AOL
  'aol.com','aol.fr',

  // Autres
  'mail.com','yandex.com','yandex.fr','zoho.com'
]);

// --- RACINES À BLOQUER ---
const FREE_ROOTS = new Set([
  'gmail','googlemail',
  'hotmail','outlook','live','msn',
  'yahoo','ymail',
  'orange','wanadoo','voila','laposte',
  'sfr','bbox','bouyguestelecom','free',
  'aliceadsl','club-internet','numericable','neuf',
  'proton','gmx',
  'icloud','me','mac',
  'aol',
  'mail','yandex','zoho'
]);

const BAD_QUERIES = new Set([
  'contact','info','bonjour','hello','support','sav','service'
]);

function domainFromEmail(email='') {
  const m = (email || '').toLowerCase().match(/@([a-z0-9.-]+\.[a-z]{2,})$/);
  return m ? m[1].replace(/^www\./,'') : null;
}

function rootFromDomain(domain='') {
  if (!domain) return null;
  const parts = domain.split('.').filter(Boolean);
  if (parts.length >= 2) return parts[parts.length - 2];
  return parts[0] || null;
}

function rootFromUrl(url='') {
  if (!url) return null;
  try {
    const u = new URL(url);
    const host = (u.hostname || '').toLowerCase().replace(/^www\./,'');
    return rootFromDomain(host);
  } catch {
    return null;
  }
}

function cleanText(s='') {
  return (s || '').toString().trim().replace(/\s+/g,' ');
}

function sanitizeQuery(q='') {
  const v = cleanText(q).toLowerCase();
  if (!v) return null;
  if (v.length < 3) return null;
  if (BAD_QUERIES.has(v)) return null;
  if (FREE_DOMAINS.has(v)) return null;
  if (FREE_ROOTS.has(v)) return null;
  if (FREE_DOMAINS.has(v + '.com') || FREE_DOMAINS.has(v + '.fr')) return null;
  return cleanText(q);
}

return items.map(item => {

  const j = item.json;

  const email = j.Email || j.email || '';
  const emailDomain = j.email_domain || domainFromEmail(email);
  const emailRoot = rootFromDomain(emailDomain);

  const site = j["Site internet"] || '';
  const siteRoot = rootFromUrl(site);

  const companyQ_raw = j.company_query || '';
  const companyQ = sanitizeQuery(companyQ_raw);

  const nameQ = sanitizeQuery(j.Nom || '');

  let retry_query = null;
  let retry_source = null;

  // 1️⃣ Email domain professionnel
  if (
    emailDomain &&
    !FREE_DOMAINS.has(emailDomain) &&
    emailRoot &&
    !FREE_ROOTS.has(emailRoot.toLowerCase())
  ) {
    retry_query = sanitizeQuery(emailRoot);
    retry_source = 'email_domain_root';
  }

  // 2️⃣ Website domain
  if (!retry_query && siteRoot) {
    const cleanSiteRoot = sanitizeQuery(siteRoot);
    if (cleanSiteRoot) {
      retry_query = cleanSiteRoot;
      retry_source = 'website_domain_root';
    }
  }

  // 3️⃣ company_query fallback
  if (!retry_query && companyQ) {
    retry_query = companyQ;
    retry_source = 'company_query';
  }

  // 4️⃣ Nom fallback
  if (!retry_query && nameQ) {
    retry_query = nameQ;
    retry_source = 'nom_fallback';
  }

  // 🚨 Si retry_query identique à company_query → annule
  if (
    retry_query &&
    companyQ &&
    retry_query.toLowerCase() === companyQ.toLowerCase()
  ) {
    retry_query = null;
    retry_source = null;
  }

  j.retry_query = retry_query;
  j.retry_source = retry_source;

  return item;
});

// Pick Best Match (retry) - simple
// But: récupérer un SIREN si Pappers renvoie au moins 1 résultat

return items.map(item => {
  // selon n8n, la réponse HTTP est souvent directement dans item.json
  // et contient "resultats"
  const resultats = item.json.resultats || [];

  const best = Array.isArray(resultats) && resultats.length > 0 ? resultats[0] : null;

  if (best?.siren) {
    item.json.SIREN = best.siren;
    item.json.pappers_ok = true;
    item.json.pappers_match_source = "retry_email_domain_root";
  } else {
    item.json.SIREN = null;
    item.json.pappers_ok = false;
    item.json.pappers_match_source = "retry_failed";
  }

  return item;
});

function isFreeEmail(email='') {
  const d = (email.split('@')[1] || '').toLowerCase();
  return ['gmail.com','yahoo.com','hotmail.com','outlook.com','live.com','icloud.com','aol.com','proton.me','protonmail.com'].includes(d);
}

return items.map(item => {
  const j = item.json;

  let score = 0;

  // signaux business simples
  if (j["Site internet"]) score += 15;
  if (j["Email"] && !isFreeEmail(j["Email"])) score += 20;
  if (j.phone_norm || j["Téléphone international"]) score += 10;
  if (j["Adresse complète"] && j["Code postal"]) score += 15;

  // réseaux sociaux (max +15)
  const socials = ["Lien Facebook","Lien Instagram","Lien Linkedin","Lien Youtube","Lien Twitter"];
  let soc = 0;
  for (const k of socials) if (j[k]) soc += 5;
  score += Math.min(15, soc);

  j.SIREN = null;
  j.lead_status = "NO_SIREN";
  j.lead_score_partial = score;

  // décision
  if (score >= 45) j.next_action = "KEEP_PROSPECT";
  else if (score >= 30) j.next_action = "LOW_PRIORITY";
  else j.next_action = "DISCARD_LOW_SIGNAL";

  // debug utile
  j.pappers_match_source = j.pappers_match_source || "retry_failed";
  j.pappers_ok = false;

  return item;
});

function clean(s){ return (s || "").toString().trim().toLowerCase(); }

const GENERIC = new Set([
  "contact","bonjour","hello","info","infos","support","sav","service","admin","office",
  "commercial","vente","sales","booking","rdv","resa","reservation","team","equipe",
  "direction","recrutement","rh","billing","facturation","compta","accounting",
  "noreply","no-reply","do-not-reply","donotreply","webmaster","postmaster"
]);

function splitLocalpart(lp){
  const s = (lp || "")
    .toString()
    .replace(/[._\-+]/g, " ")
    .replace(/\d+/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();
  return s ? s.split(" ").filter(Boolean) : [];
}

function looksGenericToken(t){
  if (!t) return false;
  if (GENERIC.has(t)) return true;
  // générique en préfixe/suffixe: contactparis, infosalon, sav2024
  for (const g of GENERIC) {
    if (t.startsWith(g) || t.endsWith(g)) return true;
  }
  return false;
}

function isGeneric(tokens){
  if (!tokens.length) return true;
  return tokens.slice(0,2).some(looksGenericToken);
}

function capName(s){
  if (!s) return "";
  return s.charAt(0).toUpperCase() + s.slice(1);
}

return items.map(item => {
  const j = item.json;
  const email = clean(j["Email"]);
  const local = email.includes("@") ? email.split("@")[0] : "";
  const tokens = splitLocalpart(local);

  let prenom = null;
  let nom = null;
  let confidence = 10;

  const generic = isGeneric(tokens);

  if (!generic) {
    if (tokens.length === 1) {
      prenom = tokens[0];
      confidence = 40;
    } else if (tokens.length >= 2) {
      prenom = tokens[0];
      nom = tokens[tokens.length - 1];
      confidence = 70;
      if (tokens.length === 2) confidence = 80;
    }
  } else {
    confidence = 0;
  }

  // token collé long (ex: jeannedarc) => moins fiable
  if (tokens.length === 1 && tokens[0].length >= 10 && !generic) {
    confidence = Math.min(confidence, 25);
  }

  const contact_display_name =
    confidence >= 60
      ? [capName(prenom), capName(nom)].filter(Boolean).join(" ")
      : null;

  return {
    json: {
      ...j,
      email_localpart: local,
      email_tokens: tokens,
      contact_is_generic: generic,
      contact_prenom_guess: prenom ? capName(prenom) : null,
      contact_nom_guess: nom ? capName(nom) : null,
      contact_confidence: confidence,
      contact_display_name
    }
  };
});

