let text = $json.textPlain || "";

// Decode les caractères mal encodés
text = text
  .replace(/Ã©/g, 'é')
  .replace(/Ã¨/g, 'è')
  .replace(/Ãª/g, 'ê')
  .replace(/Ã /g, 'à')
  .replace(/Ã®/g, 'î')
  .replace(/Ã´/g, 'ô')
  .replace(/Ã¹/g, 'ù')
  .replace(/Ã»/g, 'û')
  .replace(/Ã§/g, 'ç')
  .replace(/â€™/g, "'")
  .replace(/â€œ/g, '"')
  .replace(/â€/g, '"');

// Coupe avant la partie citée
text = text.split(/\r?\nLe .+ a [eé]crit/)[0];
text = text.split(/\n>/)[0];
text = text.trim();

// Extrait le in-reply-to
const inReplyTo = $json.metadata?.["in-reply-to"] || 
                  $json.metadata?.["references"] || null;

return [{
