    subject: $json.subject,
    from: $json.from,
    email: $json.from.match(/<(.+?)>/)?.[1] || null,
    text: text,
    in_reply_to: inReplyTo
  }
}];

// Extraction des métriques financières depuis Pappers v2
function toInt(x) {
  if (x === null || x === undefined) return null;
  const n = Number(x);
  return Number.isFinite(n) ? Math.trunc(n) : null;
}

const output = [];

for (const item of items) {
  const c = item.json;

  const finances = Array.isArray(c.finances) ? c.finances : [];
  const etablissements = Array.isArray(c.etablissements) ? c.etablissements : [];

  // Récupère le CA de la dernière année disponible
  let ca_latest = null;
  let ca_year = null;
  const caKeys = ['chiffre_affaires', 'ca', 'turnover', 'revenue'];
  const sortedFinances = [...finances].sort((a, b) => (b.annee ?? 0) - (a.annee ?? 0));
  for (const f of sortedFinances) {
    for (const k of caKeys) {
      if (f[k] !== undefined && f[k] !== null) {
        ca_latest = toInt(f[k]);
        ca_year = f.annee ?? null;
        break;
      }
    }
    if (ca_latest !== null) break;
  }

  // Résultat net dernière année
  let resultat_net = null;
  if (sortedFinances.length > 0) {
    const f0 = sortedFinances[0];
    resultat_net = toInt(f0.resultat_net ?? f0.net_income ?? null);
  }

  output.push({
    json: {
      siren: c.siren ?? null,
      siret_siege: c.siret_siege ?? null,
      nom_entreprise: c.nom_entreprise ?? null,
      forme_juridique: c.forme_juridique ?? null,
      code_naf: c.code_naf ?? null,
      libelle_code_naf: c.libelle_code_naf ?? null,

      // Taille
      effectif: toInt(c.tranche_effectif_salarie ?? c.effectif ?? null),
      effectif_label: c.tranche_effectif_salarie_label ?? null,
      nb_etablissements: etablissements.length,

      // Financiers
      capital_social: toInt(c.capital ?? null),
      capital_devise: c.devise_capital ?? 'EUR',
      ca_latest,
      ca_year,
      resultat_net,
      nb_annees_finances: finances.length,

      // Enrichissement brut (pour debug)
      _raw_finances_count: finances.length,
      _pappers_ok: true
    }
  });
}

return output;

const items = $input.all();

let ig = {};
let fb = {};

for (const item of items) {
  const d = item.json;

  // Identifier Instagram par la présence de followersCount ou username Instagram
  if (d.followersCount !== undefined || d.username !== undefined) {
    ig = d;
  }

  // Identifier Facebook par la présence de pageName ou facebookUrl
  if (d.pageName !== undefined || d.facebookUrl !== undefined) {
    fb = d;
  }
}

return [{
  json: {
    // Instagram
    instagram_followers: ig.followersCount ?? null,
    instagram_following: ig.followsCount ?? null,
    instagram_posts_count: ig.postsCount ?? null,
    instagram_username: ig.username ?? null,
    instagram_is_verified: ig.verified ?? false,
    instagram_is_business: ig.isBusinessAccount ?? false,
    instagram_ok: !!ig.username,

    // Facebook
    facebook_followers: fb.followers ?? null,
    facebook_likes: fb.likes ?? null,
    facebook_rating: fb.ratingOverall ?? null,
    facebook_rating_count: fb.ratingCount ?? null,
    facebook_page_name: fb.pageName ?? null,
    facebook_is_running_ads: (fb.ad_status ?? '').includes('currently running'),
    facebook_ok: !!fb.pageName,
  }
}];

const d = $json;
const config = d.scoring_config;

// --- Données brutes ---
const effectif = d.effectif ?? 0;
const ca = d.ca_latest ?? 0;
const capital = d.capital_social ?? 0;
const ig_followers = d.instagram_followers ?? 0;
const fb_followers = d.facebook_followers ?? 0;
const libelle_naf = (d.libelle_code_naf ?? '').toLowerCase();

// --- Config ---
const vip_cats = (config.vip_categories?.seuil ?? '').toLowerCase().split(',').map(s => s.trim());

// --- Court-circuit catégorie NAF ---
const is_vip_category = config.vip_categories?.actif 
  ? vip_cats.some(cat => libelle_naf.includes(cat))
  : false;

// --- Signaux ---
const signaux = [];

if (config.workforce?.actif && effectif >= config.workforce.seuil) {
  signaux.push(`effectif ≥ ${config.workforce.seuil}`);
}
if (config.ca?.actif && ca >= config.ca.seuil) {
  signaux.push(`CA ≥ ${config.ca.seuil}€`);
}
if (config.capital?.actif && capital >= config.capital.seuil) {
  signaux.push(`capital ≥ ${config.capital.seuil}€`);
}
if (config.instagram_followers?.actif && ig_followers >= config.instagram_followers.seuil) {
  signaux.push(`Instagram ≥ ${config.instagram_followers.seuil}`);
}
// Facebook bonus (pas dans config mais utile)
if (fb_followers >= 10000) {
  signaux.push(`Facebook ≥ 10K`);
}

// --- Décision VIP ---
const is_vip = is_vip_category || signaux.length >= 1;
const priorite = is_vip ? 'VIP' : 'STANDARD';

const raisons = [];
if (is_vip_category) raisons.push(`catégorie NAF: ${libelle_naf}`);
raisons.push(...signaux);

return [{
  json: {
    // Lead ID
    siren: d.siren,
    nom_entreprise: d.nom_entreprise,

    // Données enrichissement
    effectif: d.effectif,
    ca_latest: d.ca_latest,
    ca_year: d.ca_year,
    capital_social: d.capital_social,
    code_naf: d.code_naf,
    libelle_code_naf: d.libelle_code_naf,

    // Social
    instagram_followers: ig_followers,
    instagram_username: d.instagram_username,
    facebook_followers: fb_followers,
    facebook_page_name: d.facebook_page_name,
    facebook_is_running_ads: d.facebook_is_running_ads,
    facebook_rating: d.facebook_rating,

    // Scoring
    priorite,
    is_vip,
    nb_signaux_vip: signaux.length,
    raisons_vip: raisons.join(' | '),
    is_vip_category,

    // Meta
    enrichissement_date: new Date().toISOString(),
  }
}];

// Agrège les 5 lignes de config en un seul objet
const config = {};
for (const item of $input.all()) {
  const signal = item.json.signal;
  config[signal] = {
    seuil: item.json.seuil,
    actif: item.json.actif
  };
}

return [{ json: { scoring_config: config } }];
